export function Original(
  spending,
  totalSpending,
  claimReduction,
  operation,
  i
) {
  var reduction = 0;
  totalSpend[i] = totalSpending;
  if (operation === "next purchase") {
    if (totalSpend[i] < 1000) totalSpend[i] += spending;
    else if (!claimReduction) totalSpend[i] += spending * 2;
    else if (totalSpend[i] >= 2000) {
      totalSpend[i] += spending * (1 - 8 / 100);
    }
  }
  if (operation === "next year") {
    if (totalSpend[i] >= 3000) {
      totalSpend[i] = totalSpend[i] / 4;
    } else totalSpend[i] = 0;
  }
  spending = 0;
  if (totalSpend[i] >= 1000 && totalSpend[i] < 2000) reduction = 5;
  else if (totalSpend[i] >= 2000) reduction = 8;
  return {
    totalSpending: totalSpend[i],
    reduction: reduction,
    spending: spending,
  };
}

